    if any(s == target for s in state):
        return True
    if depth == 0:
        return False
    key = (state, depth)
    if key in memo:
        return memo[key]

    for idx, donor in enumerate(state):
        others = [state[i] for i in range(3) if i != idx]
        # Generate splits: critical + systematic
        splits = set()
        # critical
        for p in [target, donor - target,
                  donor + others[1] - target, target - others[0],
                  donor + others[0] - target, target - others[1]]:
            if 0 < p < donor:
                splits.add(p)
        # systematic fractions
        for i in range(1, split_denom):
            splits.add(Fraction(i, split_denom) * donor)
        for num in [1,2,3,5]:
